  1→import React, {useCallback, useMemo, useRef, useState} from 'react';
  2→import {
  3→  ActivityIndicator,
  4→  Alert,
  5→  Image,
  6→  Pressable,
  7→  ScrollView,
  8→  StyleSheet,
  9→  Text,
 10→  TextInput,
 11→  View,
 12→} from 'react-native';
