 46→const PAGE_SIZE = 10;
 47→
 48→const QUICK_ACTIONS = [
 49→  {key: 'all', label: 'All'},
 50→  {key: 'journal', label: 'Journals'},
 51→  {key: 'canvas', label: 'Canvas'},
 52→  {key: 'freedom_wall', label: 'Freedom Wall'},
