 56→export function HomeFeedScreen({navigation}: Props) {
 57→  const {user, session} = useAuth();
 58→  const {colors} = useTheme();
 59→  const token = session?.access_token ?? '';
 60→  const [refreshing, setRefreshing] = useState(false);
 61→  const [activeFilter, setActiveFilter] = useState('all');
 62→
 63→  const feedQuery = useInfiniteQuery({
 64→    queryKey: ['feed', user?.id],
 65→    queryFn: ({pageParam}) =>
 66→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 67→    initialPageParam: null as string | null,
 68→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 69→  });
 70→
 71→  const reactionMutation = useMutation({
 72→    mutationFn: async ({
 73→      journalId,
 74→      receiverId,
 75→      reactionType,
 76→    }: {
 77→      journalId: string;
 78→      receiverId: string;
 79→      reactionType: string;
 80→    }) => {
 81→      if (!token) throw new Error('Please log in to react.');
 82→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 83→    },
 84→    onMutate: async ({journalId, reactionType}) => {
 85→      await queryClient.cancelQueries({queryKey: ['feed']});
 86→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 87→        ['feed', user?.id],
 88→      );
 89→      if (prev) {
 90→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 91→          ['feed', user?.id],
 92→          old => {
 93→            if (!old) return old;
 94→            return {
 95→              ...old,
 96→              pages: old.pages.map(page => ({
 97→                ...page,
 98→                data: page.data.map(item => {
 99→                  if (item.id !== journalId) return item;
100→                  const removing = item.user_reaction === reactionType;
101→                  const currentCount =
102→                    (item.reaction_count?.[0]?.count ??
103→                      item.like_count?.[0]?.count ??
104→                      item.likes_count ??
105→                      0) as number;
106→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
107→                  return {
108→                    ...item,
109→                    user_reaction: removing ? null : reactionType,
110→                    has_liked: removing ? false : true,
111→                    like_count: [{count: Math.max(0, currentCount + delta)}],
112→                  };
113→                }),
114→              })),
115→            };
116→          },
117→        );
118→      }
119→      return {prev};
120→    },
121→    onError: (_err, _vars, context) => {
122→      if (context?.prev) {
123→        queryClient.setQueryData(['feed', user?.id], context.prev);
124→      }
125→    },
126→    onSettled: () => {
127→      queryClient.invalidateQueries({queryKey: ['feed']});
128→    },
129→  });
130→
131→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
132→  const repostMutation = useRepostMutation(token);
133→
134→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
135→    if (!token) return;
136→    reactionMutation.mutate({journalId, receiverId, reactionType});
137→  };
138→
139→  const handleComment = (journalId: string) => {
140→    navigation.navigate('PostDetail', {journalId});
141→  };
142→
143→  const handleBookmark = (journalId: string) => {
144→    bookmarkMutation.mutate(journalId);
145→  };
146→
147→  const handleRepost = (journalId: string) => {
148→    Alert.alert('Repost', 'Repost this to your feed?', [
149→      {text: 'Cancel', style: 'cancel'},
150→      {text: 'Repost', onPress: () => repostMutation.mutate(journalId)},
151→    ]);
152→  };
153→
154→  const posts = useMemo(
155→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
156→    [feedQuery.data?.pages],
157→  );
158→
159→  const onRefresh = async () => {
160→    setRefreshing(true);
161→    try {
162→      await feedQuery.refetch();
163→    } finally {
164→      setRefreshing(false);
165→    }
166→  };
167→
168→  const handleQuickAction = (key: string) => {
169→    if (key === 'canvas') {
170→      navigation.navigate('Canvas');
171→    } else if (key === 'freedom_wall') {
172→      navigation.navigate('FreedomWall');
173→    } else if (key === 'universe') {
174→      navigation.navigate('Universe');
175→    } else {
176→      setActiveFilter(key);
177→    }
178→  };
179→
180→  return (
181→    <SafeAreaView
182→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
183→      edges={['top']}>
184→      {/* Branded header */}
185→      <View
186→        style={[
187→          styles.header,
188→          {borderBottomColor: colors.borderCard},
189→        ]}>
190→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
191→          iskrib
192→        </Text>
193→      </View>
194→
195→      {/* Filter chips */}
196→      <View style={styles.chipRow}>
197→        <ScrollView
198→          horizontal
199→          showsHorizontalScrollIndicator={false}
200→          contentContainerStyle={styles.chipScroll}>
201→          {QUICK_ACTIONS.map(action => (
202→            <Chip
203→              key={action.key}
204→              label={action.label}
205→              active={activeFilter === action.key}
206→              onPress={() => handleQuickAction(action.key)}
207→            />
208→          ))}
209→        </ScrollView>
210→      </View>
211→
212→      {/* Feed */}
213→      <FlatList
214→        data={posts}
215→        onRefresh={onRefresh}
216→        refreshing={refreshing}
217→        onEndReachedThreshold={0.25}
218→        onEndReached={() => {
219→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
220→            feedQuery.fetchNextPage();
221→          }
222→        }}
223→        contentContainerStyle={styles.listContent}
224→        showsVerticalScrollIndicator={false}
225→        ListEmptyComponent={
226→          feedQuery.isLoading ? (
227→            <View style={styles.skeletonList}>
228→              <PostCardSkeleton />
229→              <PostCardSkeleton />
230→              <PostCardSkeleton />
231→            </View>
232→          ) : (
233→            <EmptyState
234→              title="No posts yet"
235→              subtitle="Pull to refresh or create your first journal post."
236→            />
237→          )
238→        }
239→        ListFooterComponent={
240→          feedQuery.isFetchingNextPage ? (
241→            <View style={styles.loadingMore}>
242→              <PostCardSkeleton />
243→            </View>
244→          ) : null
245→        }
246→        keyExtractor={item => item.id}
247→        renderItem={({item}) => {
248→          const preview = extractPlainText(item.content).slice(0, 180);
249→          const likeCount = resolveCount(
250→            item.like_count,
251→            item.likes_count,
252→          );
253→          const commentCount = resolveCount(
254→            item.comment_count,
255→            item.comments_count,
256→          );
257→          const bookmarkCount = resolveCount(item.bookmark_count);
258→          const bannerImage = extractBannerImage(
259→            item.content,
260→            (item as any).images,
261→          );
262→
263→          const receiverId = item.user_id ?? item.users?.id ?? '';
264→
265→          const handleAuthorPress = () => {
266→            const authorId = item.users?.id ?? item.user_id;
267→            if (!authorId) return;
268→            if (authorId === user?.id) {
269→              navigation.navigate('Main' as any, {screen: 'Profile'});
270→            } else {
271→              navigation.navigate('VisitProfile', {
272→                userId: authorId,
273→                username: item.users?.username ?? undefined,
274→              });
275→            }
276→          };
277→
278→          return (
279→            <PostCard
280→              title={item.title || 'Untitled Post'}
281→              bodyPreview={preview || 'No preview text available.'}
282→              authorName={item.users?.name || 'Unknown author'}
283→              authorAvatar={item.users?.image_url}
284→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
285→              bannerImage={bannerImage}
286→              postType={item.post_type}
287→              likeCount={likeCount}
288→              commentCount={commentCount}
289→              bookmarkCount={bookmarkCount}
290→              userReaction={item.user_reaction}
291→              isBookmarked={!!item.has_bookmarked}
292→              onReact={type => handleReact(item.id, receiverId, type)}
293→              onComment={() => handleComment(item.id)}
294→              onBookmark={() => handleBookmark(item.id)}
295→              onRepost={() => handleRepost(item.id)}
296→              onPress={() =>
297→                navigation.navigate('PostDetail', {journalId: item.id})
298→              }
299→              onAuthorPress={handleAuthorPress}
300→            />
301→          );
302→        }}
303→        ItemSeparatorComponent={() => <View style={styles.separator} />}
304→      />
305→
306→      {/* FAB Write Button */}
307→      <Pressable
308→        onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
309→        style={({pressed}) => [
310→          styles.fab,
311→          {backgroundColor: colors.accentAmber},
312→          shadows(colors).elevated,
313→          pressed && styles.fabPressed,
314→        ]}>
315→        <PenIcon size={22} color="#1A1612" />
316→      </Pressable>
317→    </SafeAreaView>
318→  );
319→}
