  1→import React, {useMemo} from 'react';
  2→import {Alert, FlatList, StyleSheet, View} from 'react-native';
  3→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
  4→import {useNavigation} from '@react-navigation/native';
  5→import type {NativeStackNavigationProp} from '@react-navigation/native-stack';
  6→import {PostCard} from '../../components/PostCard/PostCard';
  7→import {PostCardSkeleton} from '../../components/SkeletonLoader';
  8→import {EmptyState} from '../../components/EmptyState';
  9→import {
 10→  extractPlainText,
 11→  extractBannerImage,
 12→  resolveCount,
 13→  getNextCursor,
 14→} from '../../lib/utils/journalHelpers';
 15→import {mobileApi, type CursorPage, type JournalItem} from '../../lib/api/mobileApi';
 16→import {socialApi} from '../../lib/api/socialApi';
 17→import {queryClient} from '../../lib/queryClient';
 18→import {useAuth} from '../../features/auth/AuthProvider';
 19→import {useBookmarkMutation, useRepostMutation} from '../../hooks/useSocialMutations';
 20→import {spacing} from '../../theme/spacing';
 21→import type {RootStackParamList} from '../../navigation/types';
 22→
 23→const PAGE_SIZE = 10;
 24→
 25→interface ProfileWritingsTabProps {
 26→  userId: string;
 27→  headerComponent?: React.ReactElement;
 28→}
 29→
 30→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 31→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 32→  const {user, session} = useAuth();
 33→  const token = session?.access_token ?? '';
 34→
 35→  const query = useInfiniteQuery({
 36→    queryKey: ['profileWritings', userId],
 37→    queryFn: ({pageParam}) =>
 38→      mobileApi.getUserJournals(token, userId, pageParam ?? null, PAGE_SIZE),
 39→    initialPageParam: null as string | null,
 40→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 41→  });
 42→
 43→  const queryKey = ['profileWritings', userId];
 44→
 45→  const reactionMutation = useMutation<
 46→    {message?: string},
 47→    Error,
 48→    {journalId: string; receiverId: string; reactionType: string},
 49→    {prev?: {pages: CursorPage<JournalItem>[]}}
 50→  >({
 51→    mutationFn: async ({journalId, receiverId, reactionType}) => {
 52→      if (!token) throw new Error('Please log in to react.');
 53→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 54→    },
 55→    onMutate: async ({journalId, reactionType}) => {
 56→      await queryClient.cancelQueries({queryKey});
 57→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey);
 58→      if (prev) {
 59→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey, old => {
 60→          if (!old) return old;
 61→          return {
 62→            ...old,
 63→            pages: old.pages.map(page => ({
 64→              ...page,
 65→              data: page.data.map(item => {
 66→                if (item.id !== journalId) return item;
 67→                const removing = item.user_reaction === reactionType;
 68→                const currentCount =
 69→                  (item.reaction_count?.[0]?.count ??
 70→                    item.like_count?.[0]?.count ??
 71→                    item.likes_count ??
 72→                    0) as number;
 73→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
 74→                return {
 75→                  ...item,
 76→                  user_reaction: removing ? null : reactionType,
 77→                  has_liked: removing ? false : true,
 78→                  like_count: [{count: Math.max(0, currentCount + delta)}],
 79→                };
 80→              }),
 81→            })),
 82→          };
 83→        });
 84→      }
 85→      return {prev};
 86→    },
 87→    onError: (_err, _vars, context) => {
 88→      if (context?.prev) {
 89→        queryClient.setQueryData(queryKey, context.prev);
 90→      }
 91→    },
 92→    onSettled: () => {
 93→      queryClient.invalidateQueries({queryKey});
 94→    },
 95→  });
 96→
 97→  const bookmarkMutation = useBookmarkMutation(token, queryKey);
 98→  const repostMutation = useRepostMutation(token);
 99→
100→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
101→    if (!token) return;
102→    reactionMutation.mutate({journalId, receiverId, reactionType});
103→  };
104→
105→  const handleComment = (journalId: string) => {
106→    navigation.navigate('PostDetail', {journalId});
107→  };
108→
109→  const handleBookmark = (journalId: string) => {
110→    bookmarkMutation.mutate(journalId);
111→  };
112→
113→  const handleRepost = (journalId: string) => {
114→    Alert.alert('Repost', 'Repost this to your feed?', [
115→      {text: 'Cancel', style: 'cancel'},
116→      {text: 'Repost', onPress: () => repostMutation.mutate(journalId)},
117→    ]);
118→  };
119→
120→  const posts = useMemo(
121→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
122→    [query.data?.pages],
123→  );
124→
125→  return (
126→    <FlatList
127→      data={posts}
128→      keyExtractor={item => item.id}
129→      showsVerticalScrollIndicator={false}
130→      contentContainerStyle={styles.list}
131→      ListHeaderComponent={headerComponent}
132→      onEndReachedThreshold={0.3}
133→      onEndReached={() => {
134→        if (query.hasNextPage && !query.isFetchingNextPage) {
135→          query.fetchNextPage();
136→        }
137→      }}
138→      ListEmptyComponent={
139→        query.isLoading ? (
140→          <View style={styles.skeletons}>
141→            <PostCardSkeleton />
142→            <PostCardSkeleton />
143→            <PostCardSkeleton />
144→          </View>
145→        ) : (
146→          <EmptyState
147→            title="No writings yet"
148→            subtitle="Journal posts will appear here."
149→          />
150→        )
151→      }
152→      ListFooterComponent={
153→        query.isFetchingNextPage ? (
154→          <View style={styles.footer}>
155→            <PostCardSkeleton />
156→          </View>
157→        ) : null
158→      }
159→      renderItem={({item}) => {
160→        const preview = extractPlainText(item.content).slice(0, 180);
161→        const likeCount = resolveCount(item.like_count, item.likes_count);
162→        const commentCount = resolveCount(item.comment_count, item.comments_count);
163→        const bookmarkCount = resolveCount(item.bookmark_count);
164→        const bannerImage = extractBannerImage(item.content, (item as any).images);
165→
166→        const handleAuthorPress = () => {
167→          const authorId = item.users?.id ?? item.user_id;
168→          if (!authorId) return;
169→          if (authorId === user?.id) {
170→            navigation.navigate('Main' as any, {screen: 'Profile'});
171→          } else {
172→            navigation.navigate('VisitProfile', {
173→              userId: authorId,
174→              username: item.users?.username ?? undefined,
175→            });
176→          }
177→        };
178→
179→        const receiverId = item.user_id ?? item.users?.id ?? '';
180→
181→        return (
182→          <PostCard
183→            title={item.title || 'Untitled Post'}
184→            bodyPreview={preview || 'No preview text available.'}
185→            authorName={item.users?.name || 'Unknown author'}
186→            authorAvatar={item.users?.image_url}
187→            authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
188→            bannerImage={bannerImage}
189→            postType={item.post_type ?? undefined}
190→            likeCount={likeCount}
191→            commentCount={commentCount}
192→            bookmarkCount={bookmarkCount}
193→            isBookmarked={!!item.has_bookmarked}
194→            userReaction={item.user_reaction}
195→            onReact={type => handleReact(item.id, receiverId, type)}
196→            onComment={() => handleComment(item.id)}
197→            onBookmark={() => handleBookmark(item.id)}
198→            onRepost={() => handleRepost(item.id)}
199→            onPress={() =>
200→              navigation.navigate('PostDetail', {journalId: item.id})
201→            }
202→            onAuthorPress={handleAuthorPress}
203→          />
204→        );
205→      }}
206→      ItemSeparatorComponent={() => <View style={styles.separator} />}
207→    />
208→  );
209→}
210→
211→const styles = StyleSheet.create({
212→  list: {
213→    paddingHorizontal: spacing.lg,
214→    paddingBottom: 100,
215→  },
216→  skeletons: {
217→    gap: spacing.md,
218→    paddingTop: spacing.md,
219→  },
220→  footer: {
221→    paddingTop: spacing.md,
222→  },
223→  separator: {
224→    height: spacing.md,
225→  },
226→});
