 17→  onClose: () => void;
 18→}
 19→
 20→export function ReactionPicker({
 21→  visible,
 22→  currentReaction,
 23→  onSelect,
 24→  onClose,
 25→}: ReactionPickerProps) {
 26→  const {colors} = useTheme();
 27→  const opacity = useRef(new Animated.Value(0)).current;
 28→  const scale = useRef(new Animated.Value(0.8)).current;
 29→
 30→  useEffect(() => {
 31→    if (visible) {
 32→      Animated.parallel([
 33→        Animated.timing(opacity, {
 34→          toValue: 1,
 35→          duration: 180,
 36→          useNativeDriver: true,
 37→        }),
 38→        Animated.spring(scale, {
 39→          toValue: 1,
 40→          friction: 8,
 41→          tension: 100,
 42→          useNativeDriver: true,
 43→        }),
 44→      ]).start();
 45→    } else {
 46→      Animated.timing(opacity, {
 47→        toValue: 0,
 48→        duration: 120,
 49→        useNativeDriver: true,
 50→      }).start();
 51→    }
 52→  }, [visible, opacity, scale]);
 53→
 54→  if (!visible) return null;
 55→
 56→  return (
 57→    <View style={styles.wrapper}>
 58→      {/* Overlay to capture taps outside */}
 59→      <Pressable style={styles.overlay} onPress={onClose} />
 60→
 61→      <Animated.View
 62→        style={[
 63→          styles.picker,
 64→          {
 65→            backgroundColor: colors.bgElevated,
 66→            borderColor: colors.borderCard,
 67→            opacity,
 68→            transform: [{scale}],
 69→          },
 70→        ]}>
 71→        {REACTION_TYPES.map(reaction => {
 72→          const isActive = currentReaction === reaction.type;
 73→          return (
 74→            <Pressable
 75→              key={reaction.type}
 76→              style={[
 77→                styles.emojiButton,
 78→                isActive && {backgroundColor: colors.bgPill},
 79→              ]}
 80→              onPress={() => onSelect(reaction.type)}
 81→              hitSlop={4}>
 82→              <Text style={styles.emoji}>{reaction.emoji}</Text>
 83→            </Pressable>
 84→          );
 85→        })}
 86→      </Animated.View>
 87→    </View>
 88→  );
 89→}
